  1605	func normalizeSQL(sql string) string {
  1606		var b strings.Builder
  1607		inString := false
  1608		var quote rune
  1609		spacePending := false
  1610	
  1611		runes := []rune(strings.TrimSpace(sql))
  1612		for i := 0; i < len(runes); i++ {
  1613			r := runes[i]
  1614			if inString {
  1615				b.WriteRune(r)
  1616				if r == '\\' && i+1 < len(runes) {
  1617					i++
  1618					b.WriteRune(runes[i])
  1619					continue
  1620				}
  1621				if r == quote {
  1622					if i+1 < len(runes) && runes[i+1] == quote && quote != rune(0x60) {
  1623						i++
  1624						b.WriteRune(runes[i])
  1625						continue
  1626					}
  1627					inString = false
  1628				}
  1629				continue
  1630			}
  1631	
  1632			switch r {
  1633			case '\'', '"', rune(0x60):
  1634				if spacePending && b.Len() > 0 {
  1635					b.WriteByte(' ')
  1636					spacePending = false
  1637				}
  1638				inString = true
  1639				quote = r
  1640				b.WriteRune(r)
  1641			case ' ', '\t', '\n', '\r':
