    24	// writeProgress writes a human-readable progress state to stderr.
    25	func writeProgress(cmd *cobra.Command, format string, args ...any) error {
    26		bar := progressbar.NewOptions(
    27			1,
    28			progressbar.OptionSetWriter(cmd.ErrOrStderr()),
    29			progressbar.OptionSetVisibility(false),
    30		)
    31		_, err := progressbar.Bprintf(bar, format+"\n", args...)
    32		return err
    33	}
    34	
    35	// runWithProgress runs an operation while showing an indeterminate progress state.
    36	func runWithProgress(cmd *cobra.Command, description string, run func() error) error {
    37		bar := progressbar.NewOptions(
    38			-1,
    39			progressbar.OptionSetWriter(cmd.ErrOrStderr()),
    40			progressbar.OptionSetDescription(" "+description),
    41			progressbar.OptionSpinnerType(14),
    42			progressbar.OptionThrottle(100*time.Millisecond),
    43			progressbar.OptionClearOnFinish(),
    44		)
    45		if err := bar.RenderBlank(); err != nil {
    46			return err
    47		}
    48	
    49		stop := make(chan struct{})
    50		progressErr := make(chan error, 1)
    51		go func() {
    52			ticker := time.NewTicker(100 * time.Millisecond)
    53			defer ticker.Stop()
    54			for {
    55				select {
    56				case <-ticker.C:
    57					if err := bar.Add(1); err != nil {
    58						progressErr <- err
    59						return
    60					}
    61				case <-stop:
    62					progressErr <- nil
    63					return
    64				}
    65			}
    66		}()
    67	
    68		runErr := run()
    69		close(stop)
    70		spinnerErr := <-progressErr
    71		finishErr := bar.Finish()
    72		if runErr != nil {
    73			return runErr
    74		}
    75		if spinnerErr != nil {
    76			return spinnerErr
    77		}
    78		return finishErr
    79	}

