   427	
   428	// topologicalSort sorts tables so that child tables come before parent tables.
   429	// This ensures that DELETE operations respect foreign key / interleave constraints.
   430	func topologicalSort(tables []tableRelation) []string {
   431		// Build a map of parent -> children.
   432		children := make(map[string][]string)
   433		var roots []string
   434	
   435		for _, t := range tables {
   436			if t.parent == "" {
   437				roots = append(roots, t.name)
   438			} else {
   439				children[t.parent] = append(children[t.parent], t.name)
   440			}
   441		}
   442	
   443		// DFS post-order: children before parents.
   444		var result []string
   445		visited := make(map[string]bool)
   446		var visit func(name string)
   447		visit = func(name string) {
   448			if visited[name] {
   449				return
   450			}
   451			visited[name] = true
   452			for _, child := range children[name] {
   453				visit(child)
   454			}
   455			result = append(result, name)
   456		}
   457	
   458		for _, root := range roots {
   459			visit(root)
   460		}
   461	
   462		// Add any orphan tables not reachable from roots.
   463		for _, t := range tables {
   464			if !visited[t.name] {
   465				visit(t.name)
   466			}
   467		}
   468	
   469		return result
   470	}

