    24	
    25	// writeProgress writes a human-readable progress state to stderr.
    26	func writeProgress(cmd *cobra.Command, format string, args ...any) error {
    27		_, err := fmt.Fprintf(cmd.ErrOrStderr(), format+"\n", args...)
    28		return err
    29	}
    30	
    31	// runWithProgress runs an operation while showing an indeterminate progress state.
    32	func runWithProgress(cmd *cobra.Command, description string, run func() error) error {
    33		bar := progressbar.NewOptions(
    34			-1,
    35			progressbar.OptionSetWriter(cmd.ErrOrStderr()),
    36			progressbar.OptionSetDescription(" "+description),
    37			progressbar.OptionSpinnerType(14),
    38			progressbar.OptionThrottle(100*time.Millisecond),
    39			progressbar.OptionClearOnFinish(),
    40		)
    41		if err := bar.RenderBlank(); err != nil {
    42			return err
    43		}
    44	
    45		stop := make(chan struct{})
    46		progressErr := make(chan error, 1)
    47		go func() {
    48			ticker := time.NewTicker(100 * time.Millisecond)
    49			defer ticker.Stop()
    50			for {
    51				select {
    52				case <-ticker.C:
    53					if err := bar.Add(1); err != nil {
    54						progressErr <- err
    55						return
    56					}
    57				case <-stop:
    58					progressErr <- nil
    59					return
    60				}
    61			}
    62		}()
    63	
    64		runErr := run()
    65		close(stop)
    66		<-progressErr
    67		finishErr := bar.Finish()
    68		if runErr != nil {
    69			return runErr
    70		}
    71		return nil
    72	}
