func isSQLQuote(r rune) bool {
	return r == '\'' || r == '"' || r == rune(0x60)
}

func appendSQLQuotedLiteral(b *strings.Builder, runes []rune, start int, raw bool) int {
	quote := runes[start]
	triple := quote != rune(0x60) && start+2 < len(runes) && runes[start+1] == quote && runes[start+2] == quote
	b.WriteRune(quote)
	if triple {
		b.WriteRune(quote)
		b.WriteRune(quote)
		start += 2
	}

	for i := start + 1; i < len(runes); i++ {
		r := runes[i]
		b.WriteRune(r)

		if triple {
			if r == quote && i+2 < len(runes) && runes[i+1] == quote && runes[i+2] == quote {
				b.WriteRune(runes[i+1])
				b.WriteRune(runes[i+2])
				return i + 2
			}
			continue
		}

		if !raw && quote != rune(0x60) && r == '\\' && i+1 < len(runes) {
			i++
			b.WriteRune(runes[i])
			continue
		}
		if r == quote {
			if quote != rune(0x60) && i+1 < len(runes) && runes[i+1] == quote {
				i++
				b.WriteRune(runes[i])
				continue
			}
			return i
		}
	}
	return len(runes) - 1
}

func writeQuotedSQL(b *strings.Builder, runes []rune, start int, raw bool) int {
	quote := runes[start]
	triple := quote != rune(0x60) &&
		start+2 < len(runes) &&
		runes[start+1] == quote &&
		runes[start+2] == quote

	b.WriteRune(quote)
	if triple {
		b.WriteRune(quote)
		b.WriteRune(quote)
	}

	i := start
	if triple {
		i += 3
	} else {
		i++
	}
	for i < len(runes) {
		r := runes[i]
		b.WriteRune(r)

		if triple {
			if r == quote && i+2 < len(runes) && runes[i+1] == quote && runes[i+2] == quote {
				i++
				b.WriteRune(runes[i])
				i++
				b.WriteRune(runes[i])
				return i
			}
			i++
			continue
		}

		if !raw && quote != rune(0x60) && r == '\\' && i+1 < len(runes) {
			i++
			b.WriteRune(runes[i])
			i++
		})
	}
}

